import { NextResponse } from "next/server";
import { query } from "@/lib/db";

export async function GET(req: Request) {
  const { searchParams } = new URL(req.url);
  const level = searchParams.get("level") || "";
  const search = searchParams.get("search") || "";

  const conditions: string[] = [];
  const params: unknown[] = [];
  let idx = 1;

  if (level) {
    conditions.push(`cl.level_key = $${idx++}`);
    params.push(level);
  }
  if (search) {
    conditions.push(`t.name ILIKE $${idx++}`);
    params.push(`%${search}%`);
  }

  const where = conditions.length > 0 ? `WHERE ${conditions.join(" AND ")}` : "";

  const rows = await query(
    `SELECT
      t.id,
      t.name,
      cl.display_name AS level,
      cl.level_key AS "levelKey",
      COALESCE(c.name, '') AS conference,
      (SELECT COUNT(DISTINCT pts.player_id)::int
       FROM player_team_seasons pts
       JOIN team_seasons ts2 ON ts2.id = pts.team_season_id
       WHERE ts2.team_id = t.id
      ) AS "playerCount",
      (SELECT COUNT(DISTINCT g.id)::int
       FROM games g
       JOIN team_seasons ts3 ON ts3.team_id = t.id
       WHERE g.home_team_season_id = ts3.id OR g.away_team_season_id = ts3.id
      ) AS "gameCount",
      (SELECT TO_CHAR(MAX(g2.game_date), 'YYYY-MM-DD')
       FROM games g2
       JOIN team_seasons ts4 ON ts4.team_id = t.id
       WHERE g2.home_team_season_id = ts4.id OR g2.away_team_season_id = ts4.id
      ) AS "lastUpdated"
    FROM teams t
    JOIN competitive_levels cl ON cl.id = t.competitive_level_id
    JOIN team_seasons ts ON ts.team_id = t.id
    LEFT JOIN conferences c ON c.id = t.conference_id
    ${where}
    ORDER BY t.name`,
    params
  );

  const result = rows.map((r: Record<string, unknown>) => {
    const gameCount = r.gameCount as number;
    const playerCount = r.playerCount as number;
    let coverageStatus: string;
    if (gameCount >= 20 && playerCount >= 5) {
      coverageStatus = "Complete";
    } else if (gameCount > 0 || playerCount > 0) {
      coverageStatus = "Partial";
    } else {
      coverageStatus = "Missing";
    }
    return { ...r, coverageStatus };
  });

  return NextResponse.json(result);
}
